"use strict";(self.webpackChunkdocusaurus_knowledge_base=self.webpackChunkdocusaurus_knowledge_base||[]).push([[68782],{83625(e,t,r){r.r(t),r.d(t,{assets:()=>c,contentTitle:()=>a,default:()=>l,frontMatter:()=>n,metadata:()=>s,toc:()=>h});let s=JSON.parse('{"id":"6\u3001EY/IFRIC\uFF1ACompilation of Agenda Decisions/IFRS 15 Revenue from Contracts with Customers/principal-versus-agent-software-rese-25f569f589","title":"Principal versus Agent\uFF1ASoftware Reseller (IFRS 15)","description":"May 2022","source":"@site/knowledge/6\u3001EY/IFRIC\uFF1ACompilation of Agenda Decisions/IFRS 15 Revenue from Contracts with Customers/Principal versus Agent\uFF1ASoftware Reseller (IFRS 15).md","sourceDirName":"6\u3001EY/IFRIC\uFF1ACompilation of Agenda Decisions/IFRS 15 Revenue from Contracts with Customers","slug":"/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ifrs-15-revenue-from-contracts-with--f8999a754b/principal-versus-agent-software-rese-25f569f589","permalink":"/docs/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ifrs-15-revenue-from-contracts-with--f8999a754b/principal-versus-agent-software-rese-25f569f589","draft":false,"unlisted":false,"tags":[],"version":"current","sidebarPosition":4,"frontMatter":{"id":"principal-versus-agent-software-rese-25f569f589","title":"Principal versus Agent\uFF1ASoftware Reseller (IFRS 15)","slug":"/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ifrs-15-revenue-from-contracts-with--f8999a754b/principal-versus-agent-software-rese-25f569f589","sidebar_position":4},"sidebar":"knowledgeSidebar","previous":{"title":"Costs to Fulfil a Contract (IFRS 15)","permalink":"/docs/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ifrs-15-revenue-from-contracts-with--f8999a754b/costs-to-fulfil-a-contract-ifrs-15-6af726fae2"},"next":{"title":"Training Costs to Fulfil a Contract (IFRS 15)","permalink":"/docs/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ifrs-15-and-ias-38-4724c9dbcc/training-costs-to-fulfil-a-contract--9acf8915cc"}}');var o=r(74848),i=r(28453);let n={id:"principal-versus-agent-software-rese-25f569f589",title:"Principal versus Agent\uFF1ASoftware Reseller (IFRS 15)",slug:"/6-ey-bbb2f2ea9c/ifric-compilation-of-agenda-decision-fd4d0bbeaf/ifrs-15-revenue-from-contracts-with--f8999a754b/principal-versus-agent-software-rese-25f569f589",sidebar_position:4},a,c={},h=[];function d(e){let t={p:"p",strong:"strong",...(0,i.R)(),...e.components};return(0,o.jsxs)(o.Fragment,{children:[(0,o.jsx)(t.p,{children:"May 2022"}),"\n",(0,o.jsx)(t.p,{children:"The Committee received a request asking whether, in applying IFRS 15, a reseller of software licences is a principal or agent. In the fact pattern described in the request:"}),"\n",(0,o.jsx)(t.p,{children:"a. the reseller has a distribution agreement with a software manufacturer that:\ni. gives the reseller the right to grant (sell) the manufacturer\u2019s standard software licences to customers;\nii. requires the reseller to provide pre-sales advice to each customer\u2014before the sale of the software licences\u2014to identify the type and number of software licences that would meet the customer\u2019s needs; and\niii. provides the reseller with discretion in pricing the software licences for sale to customers.\nb. if the customer decides:\ni. to buy no software licences, it pays nothing. The reseller and the customer do not enter into an agreement.\nii. to buy a specified type and number of software licences, the reseller negotiates the selling price with the customer, places an order with the software manufacturer on behalf of the customer (and pays the manufacturer), and invoices the customer for the agreed price.\nc. the software manufacturer provides the customer with the software licences ordered\u2014issued in the customer\u2019s name\u2014via a software portal and with the key an agreement specifying the customer\u2019s right to use the software, a warranty covering the software\u2019s functionality and the term of the licence.\nd. if the reseller advises the customer to order an incorrect type or number of software licences (that fails to meet the customer\u2019s needs), the customer may not accept the licences. The reseller is unable to return unaccepted licences to the software manufacturer or sell them to another customer."}),"\n",(0,o.jsxs)(t.p,{children:[(0,o.jsx)(t.strong,{children:"Applicable requirements in IFRS 15\u2014Principal versus agent considerations"}),"\nParagraphs B34\u2013B38 set out a framework to determine whether an entity is a principal or agent. When another party is involved in providing goods or services to a customer, an\nentity determines whether the nature of its promise is a performance obligation to provide the specified goods or services itself (the entity is a principal) or to arrange for\nthose goods or services to be provided by the other party (the entity is an agent)."]}),"\n",(0,o.jsx)(t.p,{children:"Paragraph B34A states that determining the nature of its promise requires an entity to:"}),"\n",(0,o.jsx)(t.p,{children:"a. identify the specified goods or services to be provided to the customer. A specified good or service is a distinct good or service (or a distinct bundle of goods or services) to be provided to the customer (paragraph B34); and\nb. assess whether it controls each specified good or service before that good or service is transferred to the customer."}),"\n",(0,o.jsx)(t.p,{children:"An entity is a principal if it controls the specified good or service before that good or service is transferred to a customer (paragraph B35). An entity that is an agent does not control the specified good or service provided by another party before that good or service is transferred to the customer (paragraph B36)."}),"\n",(0,o.jsx)(t.p,{children:"Identifying the specified goods or services to be provided to the customer\nThe first step in identifying the specified goods or services to be provided to the customer is to assess the goods or services promised in the contract with the customer. A contract\nwith a customer generally explicitly states the goods or services that an entity promises to provide to a customer. However, the contract may also include promises that are\nimplied by an entity\u2019s customary business practices, published policies or specific statements if, at the time of entering into the contract, those promises create a valid\nexpectation of the customer that the entity will transfer a good or service to the customer (paragraph 24)."}),"\n",(0,o.jsx)(t.p,{children:"Having assessed the goods or services promised in the contract with the customer, an entity then identifies\u2014applying paragraphs 27\u201330\u2014each distinct good or service (or distinct bundle of goods or services) to be provided to the customer."}),"\n",(0,o.jsx)(t.p,{children:"Assessing whether an entity controls each specified good or service before that good or service is transferred to the customer\nWhen another party is involved in providing goods or services to a customer, paragraph B35A sets out the circumstances in which an entity is a principal\u2014one of which is when the entity obtains control of a good or another asset from the other party that it then transfers to the customer. Control of an asset refers to the ability to direct the use of, and obtain substantially all of the remaining benefits from, the asset; control includes the ability to prevent other entities from directing the use of, and obtaining the benefits from, an asset (paragraph 33)."}),"\n",(0,o.jsx)(t.p,{children:"Paragraph B37 sets out indicators to help an entity determine whether it is a principal or agent. Such indicators include, but are not limited to: (a) primary responsibility for fulfilling the promise to provide the specified good or service; (b) inventory risk before the specified good or service has been transferred to the customer or after transfer of control to the customer; and (c) discretion in establishing the price for the specified good or service. The indicators may be more or less relevant to the assessment of control depending on the nature of the specified good or service and the terms and conditions of the contract, and different indicators may provide more persuasive evidence in different contracts (paragraph B37A)."}),"\n",(0,o.jsxs)(t.p,{children:[(0,o.jsx)(t.strong,{children:"Applying IFRS 15 to the fact pattern described in the request"}),"\nIdentifying the specified goods or services to be provided to the customer In the fact pattern described in the request, the reseller\u2019s contract with the customer includes an explicit promise to provide a specified type and number of standard software licences to the customer."]}),"\n",(0,o.jsx)(t.p,{children:"The Committee observed that the pre-sales advice the reseller provides\u2014under the distribution agreement between the software manufacturer and the reseller\u2014is not an implicit promise in the contract with the customer. At the time of entering into the contract with the customer, the reseller has already provided the advice. There is no further advice to be provided by the reseller and the advice already provided will not be transferred to the customer after contract inception. Consequently, at the time of entering into the contract with the customer, there is no valid expectation of the customer that the reseller will transfer a good or service to the customer other than the standard software licences."}),"\n",(0,o.jsx)(t.p,{children:"Accordingly, the Committee concluded that, in the fact pattern described in the request, the promised goods in the reseller\u2019s contract with the customer are the standard software\nlicences. Because the standard software licences are the only promised goods in the contract with the customer, they are distinct goods to be provided to the customer. Those\nlicences are therefore the specified goods to be provided to the customer as described in paragraph B34A(a)."}),"\n",(0,o.jsx)(t.p,{children:"Assessing whether the reseller controls the standard software licences before they are transferred to the customer In the fact pattern described in the request, the reseller assesses whether it obtains control of the standard software licences from the software manufacturer before they are transferred to the customer. That assessment of control requires  consideration of the specific facts and circumstances, which include the terms and conditions of the contracts between the reseller and the customer, the reseller and the software manufacturer, and the software manufacturer and the customer."}),"\n",(0,o.jsx)(t.p,{children:"If\u2014after applying the principles and requirements on control in IFRS 15\u2014it is unclear whether the reseller is a principal or agent, the reseller considers the indicators in paragraph B37 in assessing whether it obtains control of the standard software licences from the software manufacturer before they are transferred to the customer. In the fact pattern described in the request, the Committee observed that:"}),"\n",(0,o.jsx)(t.p,{children:"a. the software licences provided to the customer exist only after the reseller places an order with the software manufacturer and the software manufacturer issues the software licences in the customer\u2019s name. The software manufacturer is responsible for the software\u2019s functionality, as well as for issuing and activating the licences. The software manufacturer is therefore responsible in those respects for fulfilling the promise to provide the licences to the customer (paragraph B37(a)).\nb. the reseller is the party that engages with the customer before and after the software licences are provided to the customer, taking responsibility for the unaccepted licences. The reseller is therefore responsible in those respects for fulfilling the promise to provide the licences to the customer (paragraph B37(a)).\nc. the reseller does not obtain a pool of software licences before entering into the contract with the customer and cannot, for example, direct the software licences to another customer. The reseller therefore has no inventory risk before the licences are provided to the customer but then has inventory risk until the customer accepts the licences (paragraph B37(b))."}),"\n",(0,o.jsx)(t.p,{children:"d. the reseller has discretion in establishing the price for the software licences (paragraph B37(c)). Pricing discretion may be less relevant to the assessment of control if, for example, the market for the software licences is such that the reseller, in effect, has limited flexibility in establishing the price."}),"\n",(0,o.jsx)(t.p,{children:"The Committee observed that the conclusion as to whether the reseller is a principal or agent depends on the specific facts and circumstances, including the terms and conditions of the relevant contracts. The reseller would apply judgement in making its overall assessment of whether it is a principal or agent\u2014including considering the relevance of the indicators to the assessment of control and the degree to which they provide evidence of control of the standard software licences before they are transferred to the customer\u2014within the context of the framework and requirements set out in paragraphs B34\u2013B38 of IFRS 15."}),"\n",(0,o.jsx)(t.p,{children:"The Committee also observed that the reseller would disclose (a) material accounting policy information in accordance with IAS 1 Presentation of Financial Statements, and (b)\ninformation required by IFRS 15, including about its performance obligations (paragraph 119) and the judgements made in applying IFRS 15 that significantly affect the determination of the amount and timing of revenue from contracts with customers (paragraph 123)."}),"\n",(0,o.jsx)(t.p,{children:"The Committee concluded that the principles and requirements in IFRS Accounting Standards provide an adequate basis for a reseller to determine whether\u2014in the fact\npattern described in the request\u2014it is a principal or agent for the standard software licences provided to a customer. Consequently, the Committee decided not to add a\nstandard-setting project to the work plan."})]})}function l(e={}){let{wrapper:t}={...(0,i.R)(),...e.components};return t?(0,o.jsx)(t,{...e,children:(0,o.jsx)(d,{...e})}):d(e)}},28453(e,t,r){r.d(t,{R:()=>n,x:()=>a});var s=r(96540);let o={},i=s.createContext(o);function n(e){let t=s.useContext(i);return s.useMemo(function(){return"function"==typeof e?e(t):{...t,...e}},[t,e])}function a(e){let t;return t=e.disableParentContext?"function"==typeof e.components?e.components(o):e.components||o:n(e.components),s.createElement(i.Provider,{value:t},e.children)}}}]);